package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File

@Singleton
class FileController @Inject() (val controllerComponents: ControllerComponents) extends BaseController {
  
  private val uploadDirectory = "uploads"
  
  def serveFile(filename: String) = Action {
    try {
      val file = new File(uploadDirectory, filename)
      val canonicalPath = file.getCanonicalPath
      
      if (!canonicalPath.startsWith(new File(uploadDirectory).getCanonicalPath + File.separator)) {
        return NotFound(views.html.error("Invalid file path"))
      }
      
      if (!file.exists() || file.isDirectory) {
        return NotFound(views.html.error("File not found"))
      }
      
      val content = Source.fromFile(file).mkString
      Ok(content).as("text/plain")
    } catch {
      case _: Exception => NotFound(views.html.error("File not found"))
    }
  }
}